// Query all customers, products, and purchases
const customersResult = await external_queryTable({ table: 'customers' });
const productsResult = await external_queryTable({ table: 'products' });
const purchasesResult = await external_queryTable({ table: 'purchases' });

const customers = customersResult.rows as any[];
const products = productsResult.rows as any[];
const purchases = purchasesResult.rows as any[];

// Create lookup maps for faster access
const productMap = new Map(products.map(p => [p.id, p]));
const customerMap = new Map(customers.map(c => [c.id, c]));

// Group data by city
const cityData = new Map<string, {
  totalRevenue: number;
  uniqueCustomers: Set<number>;
  categoryPurchaseCounts: Map<string, number>;
}>();

// Process each purchase
for (const purchase of purchases) {
  const customer = customerMap.get(purchase.customer_id);
  const product = productMap.get(purchase.product_id);

  if (customer && product) {
    const city = customer.city;

    if (!cityData.has(city)) {
      cityData.set(city, {
        totalRevenue: 0,
        uniqueCustomers: new Set(),
        categoryPurchaseCounts: new Map()
      });
    }

    const data = cityData.get(city)!;
    data.totalRevenue += purchase.total;
    data.uniqueCustomers.add(purchase.customer_id);

    const currentCount = data.categoryPurchaseCounts.get(product.category) || 0;
    data.categoryPurchaseCounts.set(product.category, currentCount + purchase.quantity);
  }
}

// Format results
const results = Array.from(cityData.entries()).map(([city, data]) => {
  // Find most purchased category
  let mostPurchasedCategory = 'N/A';
  let maxCount = 0;

  for (const [category, count] of data.categoryPurchaseCounts.entries()) {
    if (count > maxCount) {
      maxCount = count;
      mostPurchasedCategory = category;
    }
  }

  return {
    city,
    totalRevenue: data.totalRevenue.toFixed(2),
    uniqueCustomers: data.uniqueCustomers.size,
    mostPurchasedCategory
  };
}).sort((a, b) => a.city.localeCompare(b.city));

return results;
"}
